\" y1=\"360\" x2=\"156.24795985253\" y2=\"440.28764622123\" \/><text class=\"house-number\" x=\"136.71009298908\" y=\"447.98646161231\" text-anchor=\"middle\" dominant-baseline=\"central\">2<\/text><\/g><g class=\"house house-3\" data-type=\"house-cusp\" data-house-id=\"3\" data-object-id=\"house-cusp-3\"><line class=\"house-cusp-line\" x1=\"360\" y1=\"360\" x2=\"199.69661965429\" y2=\"509.21067739856\" \/><text class=\"house-number\" x=\"184.32506263484\" y=\"523.51855057377\" text-anchor=\"middle\" dominant-baseline=\"central\">3<\/text><\/g><g class=\"house house-5\" data-type=\"house-cusp\" data-house-id=\"5\" data-object-id=\"house-cusp-5\"><line class=\"house-cusp-line\" x1=\"360\" y1=\"360\" x2=\"400.12683509141\" y2=\"575.29244553757\" \/><text class=\"house-number\" x=\"403.9746137988\" y=\"595.93692661651\" text-anchor=\"middle\" dominant-baseline=\"central\">5<\/text><\/g><g class=\"house house-6\" data-type=\"house-cusp\" data-house-id=\"6\" data-object-id=\"house-cusp-6\"><line class=\"house-cusp-line\" x1=\"360\" y1=\"360\" x2=\"528.45884279663\" y2=\"499.93790867245\" \/><text class=\"house-number\" x=\"544.61243046206\" y=\"513.35661224378\" text-anchor=\"middle\" dominant-baseline=\"central\">6<\/text><\/g><g class=\"house house-8\" data-type=\"house-cusp\" data-house-id=\"8\" data-object-id=\"house-cusp-8\"><line class=\"house-cusp-line\" x1=\"360\" y1=\"360\" x2=\"563.75204014747\" y2=\"279.71235377877\" \/><text class=\"house-number\" x=\"583.28990701092\" y=\"272.01353838769\" text-anchor=\"middle\" dominant-baseline=\"central\">8<\/text><\/g><g class=\"house house-9\" data-type=\"house-cusp\" data-house-id=\"9\" data-object-id=\"house-cusp-9\"><line class=\"house-cusp-line\" x1=\"360\" y1=\"360\" x2=\"520.30338034571\" y2=\"210.78932260144\" \/><text class=\"house-number\" x=\"535.67493736516\" y=\"196.48144942623\" text-anchor=\"middle\" dominant-baseline=\"central\">9<\/text><\/g><g class=\"house house-11\" data-type=\"house-cusp\" data-house